import { z } from "zod";

// Zod schema for registration form with conditional validation
export const registrationSchema = z
  .object({
    username: z
      .string()
      .min(3, "Nome utente deve avere almeno 3 caratteri"),
    email: z.string().email("Email non valida"),
    role: z.enum(["user", "admin", "contributor"]),
    otherInfo: z.string().optional(),
    newsletter: z.boolean().optional(),
    frequency: z.enum(["daily", "weekly", "monthly"]).optional(),
    bio: z.string().optional(),
  })
  .superRefine((data, refineContext) => {
    // OtherInfo required when role is "contributor"
    if (data.role === "contributor" && (!data.otherInfo || data.otherInfo.trim() === "")) {
      refineContext.addIssue({
        code: z.ZodIssueCode.custom,
        message: "Informazioni aggiuntive richieste per i contributor",
        path: ["otherInfo"],
      });
    }

    // Frequency required when newsletter is true
    if (data.newsletter === true && !data.frequency) {
      refineContext.addIssue({
        code: z.ZodIssueCode.custom,
        message: "Frequenza newsletter richiesta",
        path: ["frequency"],
      });
    }
  });

// TypeScript type inferred from Zod schema
export type RegistrationFormData = z.infer<typeof registrationSchema>;

